import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

describe("@component", () => {
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_component
  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_01
    it("Components.<Name> with Agent type", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Agent,
        })
        namespace Components.MyAgent;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_12
    it("Components.<Name> with Service type", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Components.MyApiService;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_13
    it("Components.<Name> with Store type", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Store,
        })
        namespace Components.MyStore;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_14
    it("Components.<Name> with Sdk type", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Sdk,
        })
        namespace Components.MySdk;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_15
    it("Components.<Name> with Ui type", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Ui,
        })
        namespace Components.MyUi;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_16
    it("Service type with -cli suffix is valid", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Components.A10nCli;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_03
    it("with optional source field", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Agent,
          source: "https://github.com/example-org/my-agent",
        })
        namespace Components.MyAgent;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_04
    it("with @testing on same namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        namespace Components {
          @component(#{
            type: ComponentType.Service,
          })
          namespace DepAService {}

          @component(#{
            type: ComponentType.Agent,
          })
          @testing(Components.DepAService, #{
            approach: TestingApproach.Mock,
            reasoning: "Avoid live calls"
          })
          namespace MyAgent {}
        }
      `);
    });

    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_depends_on:Products.A10nBlueprintEngine.Features.SystemAuthoring.component_depends_on:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_testing:Products.A10nBlueprintEngine.Features.SystemAuthoring.component_depends_on:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_depends_on
    it("with @dependsOn listing other components", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        namespace Components {
          @component(#{
            type: ComponentType.Service,
          })
          namespace DepAService {}

          @component(#{
            type: ComponentType.Agent,
          })
          @dependsOn([Components.DepAService])
          namespace MyAgent {}
        }
      `);
    });

    it("Dependencies.<Dep>.<Name> legacy stub form is accepted", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Dependencies.AgUi.AgUiService;
      `);
    });

    it("Dependencies.<Dep>.Components.<Name> 4-segment form is accepted", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Dependencies.AgUi.Components.AgUiService;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_17
    it("with @uiRoute on a namespace inside @component Ui", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{
          type: ComponentType.Ui,
        })
        namespace Components.MyUi {
          @uiRoute(#{ path: "/reviews/:id" })
          namespace ReviewDetail {}
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_05
    it("namespace not starting with Components.", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Agent,
        })
        namespace MyAgent;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Components\./,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_06
    it("namespace with too many segments (Components.Foo.Bar)", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Agent,
        })
        namespace Components.Foo.Bar;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Components\./,
      });
    });

    it("4-segment namespace where segment 3 is not Components is rejected", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Dependencies.AgUi.Subsystem.AgUiService;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Components\./,
      });
    });

    it("5-segment Dependencies.<Dep>.Components.<Name>.<Extra> is rejected", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Dependencies.AgUi.Components.AgUiService.Extra;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Components\./,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_18
    it("@testing nested inside component namespace", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        namespace Components {
          @component(#{
            type: ComponentType.Service,
          })
          namespace DepAService {}

          @component(#{
            type: ComponentType.Agent,
          })
          namespace MyAgent {
            @testing(Components.DepAService, #{
              approach: TestingApproach.Mock,
              reasoning: "Avoid live calls"
            })
            namespace Nested {}
          }
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-decorator-context",
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_19
    it("unresolved inline ref in @testing reasoning", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        namespace Components {
          @component(#{
            type: ComponentType.Service,
          })
          namespace DepAService {}

          @component(#{
            type: ComponentType.Agent,
          })
          @testing(Components.DepAService, #{
            approach: TestingApproach.Mock,
            reasoning: "Uses {@GhostType} in tests"
          })
          namespace MyAgent {}
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/unresolved-inline-ref",
        message: /GhostType/,
      });
    });

    it("@dependsOn on namespace without @component or @testSuite", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Components.DepAService {}

        @dependsOn([Components.DepAService])
        namespace SomeRandomNamespace {}
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-decorator-context",
        message: /dependsOn/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_08
    it("source is not a valid URL", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Service,
          source: "internal/review",
        })
        namespace Components.ReviewApiService;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-url-format",
        message: /internal\/review/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_21
    it("source with file:// scheme is valid", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Service,
          source: "file:///path/to/local/repo",
        })
        namespace Components.ReviewApiService;
      `);
      expectDiagnostics(diagnostics, []);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_07
    it("source with ftp:// scheme is invalid", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Service,
          source: "ftp://example.com/repo",
        })
        namespace Components.ReviewApiService;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-url-format",
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_09
    it("Agent name without -agent suffix", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Agent,
        })
        namespace Components.ReviewApi;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/component-name-suffix",
        message: /-agent/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_10
    it("Service name without -service or -cli suffix", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Components.ReviewAgent;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/component-name-suffix",
        message: /-service/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_22
    it("Store name without -store suffix", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Store,
        })
        namespace Components.ReviewAgent;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/component-name-suffix",
        message: /-store/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_23
    it("Sdk name without -sdk suffix", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Sdk,
        })
        namespace Components.ReviewAgent;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/component-name-suffix",
        message: /-sdk/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T005.T005_24
    it("Ui name without -ui suffix", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Ui,
        })
        namespace Components.ReviewAgent;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/component-name-suffix",
        message: /-ui/,
      });
    });

    it("@dependsOn on operation outside @component", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Service,
        })
        namespace Components.DepAService {}

        @dependsOn([Components.DepAService])
        op orphan(): void;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /dependsOn/,
      });
    });
  });
});
